"use client";

import { useEffect, useState } from "react";
import Particles, { initParticlesEngine } from "@tsparticles/react";
import type { Engine } from "@tsparticles/engine";
import { loadAll } from "@tsparticles/all";

export default function ParticlesBackground() {
    const [init, setInit] = useState(false);

    // On attend le chargement complet de tspartciles avant de mettre setInit à vrai pour afficher les particules
    useEffect(() => {
        initParticlesEngine(async (engine: Engine) => {
            await loadAll(engine);
        }).then(() => {
            setInit(true);
        });
    }, []);

    const options: any = {
        // ===== FOND DÉGRADÉ SPATIAL =====
        background: {
            color: {
                value: "#000000",
            },
        },
        fullScreen: {
            enable: false,
        },

        // ===== ÉTOILES PRINCIPALES (scintillantes) =====
        particles: {
            number: {
                value: 300, // Beaucoup d'étoiles
                density: {
                    enable: true,
                    area: 800,
                },
            },
            // Couleurs variées (blanc, bleu, violet)
            color: {
                value: ["#ffffff", "#a8daff", "#c9b3ff"],
            },
            shape: {
                type: "circle",
            },
            // Scintillement réaliste
            opacity: {
                value: { min: 0.1, max: 1 },
                animation: {
                    enable: true,
                    speed: 3,
                    sync: false,
                },
            },
            // Tailles variées
            size: {
                value: { min: 0.5, max: 3 },
                random: true,
            },
            // Mouvement lent
            move: {
                enable: true,
                speed: 1,
                direction: "none",
                random: true,
                straight: false,
            },
        },
    };

    return (
        <div className="absolute inset-0">
            {init && (
                <Particles
                    className="absolute inset-0"
                    options={options}
                />
            )}
        </div>
    );
}